var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"아, 이쪽일 거예요. 언니를 찾으러 자주 가서 길은 다 외웠거든요.","JPN":"あ、こっちです。リタお姉ちゃんを探しによく通っていたから、道は全部覚えているんですよ。","ENG":"Oh, I think it's this way. I already memorized how to get there because I had to go looking for Rita all the time.","TWN":"啊，可能是這邊。之前經常到那裡去找姐姐，我記得路。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"그리고 그 때는 저보다 언니가 더 힘들었을 거예요. 신호가 잡히는 곳까지는 아주 멀었거든요.","JPN":"そしてあの時は私よりリタお姉ちゃんのほうが辛かったと思います。信号の場所まではかなり距離があって。","ENG":"I'm sure Rita had a much tougher time than me back then. It took forever to get to a spot where we could find the signal.","TWN":"那時候姐姐應該比我更累。距離感應到信號的地方還很遠呢。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"저도 CRF가 넉넉하진 않아서...... 침식체들을 피해 가느라 멀리 돌아가야 했어요.","JPN":"私もCRFに余裕がなくて……侵食体を避けて遠回りをする必要がありました。","ENG":"And since I was also running pretty low on CRF... We had to take the long way around to avoid the Corrupted Objects.","TWN":"我的CRF也不充足……要躲避侵蝕體，所以要繞很遠的路。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"그거 아세요? 리타 언니는 항상 저보다 늦게 잠들었어요. 술에 잔뜩 취한 채로요.","JPN":"知っていますか？　リタお姉ちゃんはいつも私より遅く寝ていたんです。ずいぶんと酔っ払ったまま。","ENG":"Did you know? Rita always went to bed later than me. Always plastered too.","TWN":"您知道嗎？麗塔姐姐總是比我睡得晚，醉醺醺的。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"가끔은 제가 자고 있는 얼굴을 그려 뒀다가 보여 주시기도 했고요.","JPN":"たまに私の寝顔を描いて、見せてくれたりもしていました。","ENG":"Sometimes, she sketched my face while I was asleep and showed it to me later.","TWN":"偶爾會畫出我睡覺時候的樣子後拿給我看。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"잠들었을 때도 얼빠지게 생겼다면서.","JPN":"寝ている時もマヌケな顔しているって。","ENG":"She teased me about how stupid I looked even when I was asleep.","TWN":"她說我睡覺的時候也很傻。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"그날...... 언니가 왜 술을 못 끊는지 알게 됐어요.","JPN":"あの日……リタお姉ちゃんがなぜお酒をやめられなくなったのかを知りました。","ENG":"That day... I learned why she couldn't quit drinking.","TWN":"那天……我知道姐姐為什麼不能戒酒了。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"엄마...... 조금만 참아...... 내가 금방 꺼내 줄게......!","JPN":"母さん……少しだけ我慢して……今すぐ出してあげるから……！","ENG":"Mom... Hang in there... I'll get you out!","TWN":"媽媽……再忍一忍……我馬上救你出來……！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"왜 아무도 도와 주지 않는 거야......! 엄마가 살려달라잖아!","JPN":"なぜ誰も助けてくれないの……！　母さんが助けてって言っているのに！","ENG":"Why isn't anyone helping? My mom needs help!","TWN":"為什麼沒人幫忙……！媽媽在求救啊！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"엄마......! 엄마......!","JPN":"母さん……！　母さん……！","ENG":"Mom! Mom!","TWN":"媽媽……！媽媽……！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":null,"text":{"KOREA":"......이마에 식은땀을 닦아 주느라 소매가 축축하게 젖을 정도였거든요.","JPN":"……額の冷や汗がびっしょりで、袖でぬぐい切れないほどでした。","ENG":"She was covered in a cold sweat, so much so that my sleeves got soaked when I patted her head dry.","TWN":"……我給她擦額頭上的冷汗時袖子都濕了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"호라이즌 대표님은 뭔가 아실 것 같아서, 잠들기 전에 무슨 일인지 물어 봤어요.","JPN":"ホライズン代表なら何か知っていそうで、寝る前に聞いてみたんです。","ENG":"I thought my boss Horizon might know something about it, so I asked her before I went to bed.","TWN":"地平線BOSS好像知道什麼，我問他睡著之前發生了什麼事。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"리타의 모친 말씀이십니까?","JPN":"リタの母親のことですか？","ENG":"Rita's mother?","TWN":"是說麗塔的母親嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"네. 잠들었을 때 언니가 저런 잠꼬대를 하는지 전혀 몰랐어요.","JPN":"はい。リタお姉ちゃんがあんな寝言を言うなんて全然知らなかったです。","ENG":"Yes. I didn't realize Rita talked in her sleep like that.","TWN":"是，我睡著的時候完全不知道姐姐會說夢話。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"평소보다 과하긴 하더군요. 침식 증후군일 가능성도 고려해야겠습니다.","JPN":"普段よりひどいですね。侵食症候群である可能性も考えなければなりません。","ENG":"It was more intense than usual. We may have to consider the possibility of Corruption Syndrome.","TWN":"是比平時嚴重了一些，可能是侵蝕症候群。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"제가 얘기했다는 건 비밀로 해 주십시오.","JPN":"私が話したというのは内緒にしてください。","ENG":"Please don't tell her that I told you this.","TWN":"不能跟她說是我告訴你的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"리타의 모친은 아르세니코 패밀리의 적대 조직이 벌인 차량 폭발 테러로 사망했습니다.","JPN":"リタの母親はアルセニコファミリーの敵対組織が起こした、車両爆発テロで死亡しました。","ENG":"Rita's mother was killed in an car bombing set up by the Arsenicos' rivals.","TWN":"麗塔的母親死於車輛爆炸，而策劃這場恐怖攻擊的人，正是阿塞妮克家族的敵對組織。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"네?","JPN":"テロ？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그러면 언니네 어머니도...... 언니처럼 무서운 분이었어요?","JPN":"それじゃあリタお姉ちゃんのお母さんも……リタお姉ちゃんみたいに怖い仕事をしていた方だったんですか？","ENG":"Then was Rita's mother... as intimidating as she is?","TWN":"那姐姐的媽媽也……是像姐姐那樣可怕的人嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"아니요. 남편을 건설업체 사장으로만 알던 사람이었다고 합니다.","JPN":"いいえ。お父さんのことは、普通の建設会社の社長として認識していたそうです。","ENG":"No. Apparently she thought her husband ran a construction business.","TWN":"不，她以為自己的丈夫只是建築企業的老闆。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그럼...... 왜 그런 짓을 한 거예요?","JPN":"なのに……どうしてそんなことに？","ENG":"Then... Why would they do such a thing to her?","TWN":"那……到底為什麼要做那種事？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"이권을 얻기 위해 수단 방법을 가리지 않는 세상입니다.","JPN":"利権を得るためには手段と方法を選ばない業界です。","ENG":"People do whatever it takes to gain the upper hand in that line of business.","TWN":"這是個為了權利不擇手段的世界。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_B_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PIRATE_FOX_A_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"조직원들에게 경고의 의미로 쓰일 수 있다면 충분히 행동으로 옮길 만한 방안이죠.","JPN":"組織員への警告という意味で、十分実行する価値があったのでしょう。","ENG":"They must have thought it would be an effective warning to the rest of the gang members.","TWN":"如果可以作為對組織成員的警告，那就是完全能夠付諸行動的方案。"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_B_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PIRATE_FOX_A_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"<color=#ffd34c>너희들 보스의 마누라도 마른 장작 꼴이 됐다. 조직원인 너희들 가족들은 어떨까?</color>","JPN":"<color=#ffd34c>ボスの妻は焼死した。組織員であるお前らの家族はどんな目にあうのだろう？</color>","ENG":"<color=#ffd34c>We even turned your boss's wife to ash. What do you think we could do to your family?</color>","TWN":"<color=#ffd34c>你們老闆的老婆都快死了。作為組織成員的你們家人又會如何？</color>"},"stage":{"bg":"MANSION","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PIRATE_FOX_B_NULL","face":"UNIT_IDLE"},"R":{"char_id":"PIRATE_FOX_A_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"대표님, 저는 리타 언니한테 힘이 되고 싶어요.","JPN":"代表、私はリタお姉ちゃんの力になりたいです。","ENG":"Boss, I'd like to help Rita.","TWN":"BOSS，我想成為麗塔姐姐的力量。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"네. 대시는 충분히 최선을 다하고 있습니다.","JPN":"はい。ダッシュは十分頑張っていますよ。","ENG":"Of course. You're trying your best already.","TWN":"嗯，黛西一直都在努力啊。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"하지만 저는 매번 사고만 치고 언니를 힘들게만 한 것 같아요.","JPN":"でも私はやらかしてばっかりで、リタお姉ちゃんに迷惑ばかりかけています。","ENG":"But I always seem to get into trouble and make life harder for her.","TWN":"但我好像每次都闖禍，讓姐姐勞累。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"언니는 괜찮다고 하지만...... 저렇게 괴로워하면서도 저한테는 그동안 한마디 안 했잖아요.","JPN":"本人は大丈夫と言っていたけど……あんなに苦しんでいるのに私には今まで何も言ってくれなくて。","ENG":"Rita says she's fine... but she never said a word about how much she's been suffering.","TWN":"雖然姐姐說沒關係……但她那麼痛苦，卻對我隻字不提。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"그렇다면 좋은 방법이 있습니다.","JPN":"それでは、いい方法があります。","ENG":"Then I have a good idea.","TWN":"既然如此，有一個好辦法。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"술집에 같이 가 주는 거죠.","JPN":"バーに付き合ってあげることです。","ENG":"You could go to the bar with her.","TWN":"跟她一起去酒館。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"술집에요?","JPN":"バーですか？","ENG":"The bar?","TWN":"酒館？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"자리에 같이 앉아 있기만 해도 충분합니다. 리타는 술 없이는 자기 마음을 털어 놓질 못하거든요.","JPN":"一緒に席に座っているだけで十分です。リタはお酒がないと、本音が言えないタイプの人ですから。","ENG":"Just sitting next to her will be enough. Rita can't share her feelings without a little liquid courage.","TWN":"一起坐著就行。麗塔不喝酒的話是無法吐露真心話的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"헤헤, 갈 수 있으면 좋겠네요. 가능성은 희박하겠지만요.","JPN":"へへ、行けたらいいですね。可能性は低いけど。","ENG":"Heh heh, that would be nice. Although given the circumstances, I doubt it'll ever happen...","TWN":"嘿嘿，如果能去就好了。不知道能不能安全回到異界。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"대시의 입에서 가능성이 희박하다는 말이 나오다니 의외로군요.","JPN":"ダッシュの口から後ろ向きな言葉が出るとは、意外ですね。","ENG":"I never thought I'd hear you express such skepticism.","TWN":"竟然能從黛西你的口中聽到這麼消極的話，還真是意外。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"뭐든 술술 풀릴 거라고 생각하진 않아요.","JPN":"すべてがうまくいくとは思いません。","ENG":"I'm not so optimistic to think everything will always work out.","TWN":"我也不是認為所有的事都能順利解決的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"저도 언니를 못 만났으면...... 여전히 엄마랑 아빠가 칭찬해 주기만 기다리면서 돈을 벌고 있었을 테니까요.","JPN":"もしリタお姉ちゃんに出会えてなかったら……\\nいまだに親がいつかは褒めてくれると信じて、\\n薄暗い家でひたすら働いていたでしょう。","ENG":"If I hadn't met Rita... I'd still be working day and night, hoping my parents would tell me I'm doing a good job.","TWN":"如果我沒遇到姐姐……可能還在等著爸爸媽媽的稱讚，每天賺錢呢。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"그러니까 조금이라도 가망이 있다면, 포기하지 않을 뿐이에요.","JPN":"だから少しでも可能性があるのなら、諦めたくないだけです。","ENG":"That's why I never give up, as long as there's even the tiniest chance.","TWN":"所以我只要有一點點可能性，就不會放棄。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DASH_HORIZON_NULL_NULL","text":{"KOREA":"포기는 언제든지 할 수 있지만 노력은 지금이 아니면 못하잖아요.","JPN":"諦めることはいつでもできるけど、努力は今じゃないとできないから。","ENG":"I could give up whenever I want, but while I still have the energy, I've got to try.","TWN":"因為隨時都可以放棄，但努力只能是在當下。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"......대시는 참 강하군요.","JPN":"……ダッシュは強いですね。","ENG":"You're a very strong person, Dash.","TWN":"……黛西真的很強呢。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"잠시 눈을 붙이시죠. 보초는 제가 서겠습니다.","JPN":"少しでも寝てください。見張りは私がやります。","ENG":"Why don't you get some shut-eye? I'll keep watch.","TWN":"休息一下吧，我來站崗。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"그날 꿈에는...... 사무실이 나왔어요.","JPN":"あの日の夢の中では……事務所にいました。","ENG":"That night... I dreamed of our office.","TWN":"那天在夢裡……夢到了事務所。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"리타 언니랑, 호라이즌 대표님이랑, 셋이서. 제가 빚을 청산했다고 축하해 주는 모습이.","JPN":"リタお姉ちゃんとホライズン代表と、3人で。私の借金完済にお祝いをする夢でした。","ENG":"It was me, Rita, and Horizon. They were congratulating me for settling all my debts.","TWN":"麗塔姐姐、地平線BOSS，我們三個。慶祝我還清債務的樣子。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"......맛있었어요. 꿈에서 먹은 카스텔라.","JPN":"……美味しかったです。夢の中で食べたカステラは。","ENG":"And it was so tasty... The sponge cake I had in the dream...","TWN":"……很好吃，在夢裡吃的海綿蛋糕。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};